const { Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell, HeadingLevel, BorderStyle, WidthType, ShadingType } = require("docx");
const fs = require("fs");

const promotionCandidates = [
  { name: "Eve Davis", department: "Engineering", salary: 80495, performance: 5 },
  { name: "Frank Miller", department: "Sales", salary: 123563, performance: 5 },
  { name: "Grace Wilson", department: "Marketing", salary: 78893, performance: 5 },
  { name: "Henry Moore", department: "HR", salary: 50851, performance: 4 },
  { name: "Jack Anderson", department: "Engineering", salary: 63396, performance: 4 }
];

const border = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const borders = { top: border, bottom: border, left: border, right: border };

const tableRows = [
  new TableRow({
    children: [
      new TableCell({ borders, shading: { fill: "D5E8F0", type: ShadingType.CLEAR }, children: [new Paragraph({ children: [new TextRun({ bold: true, text: "Name" })] })] }),
      new TableCell({ borders, shading: { fill: "D5E8F0", type: ShadingType.CLEAR }, children: [new Paragraph({ children: [new TextRun({ bold: true, text: "Department" })] })] }),
      new TableCell({ borders, shading: { fill: "D5E8F0", type: ShadingType.CLEAR }, children: [new Paragraph({ children: [new TextRun({ bold: true, text: "Salary" })] })] }),
      new TableCell({ borders, shading: { fill: "D5E8F0", type: ShadingType.CLEAR }, children: [new Paragraph({ children: [new TextRun({ bold: true, text: "Performance Score" })] })] })
    ]
  }),
  ...promotionCandidates.map(c => new TableRow({
    children: [
      new TableCell({ borders, children: [new Paragraph(c.name)] }),
      new TableCell({ borders, children: [new Paragraph(c.department)] }),
      new TableCell({ borders, children: [new Paragraph("$" + c.salary.toLocaleString())] }),
      new TableCell({ borders, children: [new Paragraph(c.performance.toString())] })
    ]
  }))
];

const doc = new Document({
  sections: [{
    children: [
      new Paragraph({ heading: HeadingLevel.HEADING_1, children: [new TextRun({ bold: true, text: "Promotion Candidates Report" })] }),
      new Table({
        width: { size: 9360, type: WidthType.DXA },
        columnWidths: [2340, 2340, 2340, 2340],
        rows: tableRows
      }),
      new Paragraph({ children: [new TextRun({ text: "\n" })] }),
      new Paragraph({
        children: [new TextRun({ 
          text: "Executive Summary: This report identifies 5 promotion candidates who have demonstrated exceptional loyalty and performance. These employees have been with the company for more than 5 years and have achieved performance scores of 4 or above. The candidates represent diverse departments including Engineering, Sales, Marketing, and HR, with salaries ranging from $50,851 to $123,563. All candidates are recommended for promotion consideration based on their proven track record and tenure. "
        })]
      })
    ]
  }]
});

Packer.toBuffer(doc).then(buffer => {
  fs.writeFileSync("outputs/promotion_report.docx", buffer);
  console.log("Created outputs/promotion_report.docx");
});
